import { FormGroup, Row, Col, Button, Label, Input, InputGroup, InputGroupText } from "reactstrap";
import React, { useState } from "react";
import { StopCircle, Check, Search } from "react-feather";
import { apiPostMethod } from "@helpers/axiosHelper";
import { errorToast } from "@helpers/appHelper";
import { apiBaseUrl } from "../../../../urlConstants";
import { useFormik } from "formik";
import { CustomTextInput, Yup, validation, CustomDropdownInput } from "../../../forms/custom-form";
import { useLoader } from "../../../../utility/hooks/useLoader";
import { PlantIdDropdown } from "../../../common/PlantIdDropdown";
import { useAuth } from "../../../../utility/hooks/useAuth";
import { statusCode } from "../../../../helper/appHelper";

const IasEmptyVehicleArrivalForm = ({ onAdded, gateInStatus, isTruck, FirstWeight }) => {
  let { showLoader, hideLoader } = useLoader();
  let { defaultPlantId } = useAuth();
  
  let screenType = "EVADP";

  const RefreshPage = () => {
    window.location.reload();
  };

  const onAdd = (status) => {
    // if (!form.isValid) {
    //   form.setSubmitting(true);
    //   form.validateForm();
    //   return;
    // }
   
    let formData = form.values;
    if(formData.plant == '' || formData.plant == undefined){
      errorToast("Please Select Plant Code ...");
      return false
    }else if(Vehicle_Number == '' || Vehicle_Number == undefined){
      errorToast("Please Enter Correct Vehicle No,Otherwise Contact SAP Team...");
      return false
    }else if(TripSheetNo == ''){
      errorToast("Please Enter TripSheet No...");
      return false
    }
    else if(DriverNo == ''){
      errorToast("Please Enter Correct Vehicle No,Otherwise Contact SAP Team...");
      return false
    }
    else if(DriverName == ''){
      errorToast("Please Enter Correct Vehicle No,Otherwise Contact SAP Team...");
      return false
    }
    if(formData.plant.value=="1111"){
     // screenType="SILOTOMILL";
    }

    let fdata = {
      DRIVER_NO: DriverNo,
      PLANT_ID: formData.plant.value,
      PLANT_NAME: formData.plant.label,
      SCREEN_TYPE: screenType,
      VEHICLE_STATUS: status,
      formType: "A",
      isTruck: isTruck,
      // tripsheetid:TripSheetNo,
      tripsheet_no:TripSheetNo,
      driver_name:DriverName,
    };

    if (isTruck) {
      fdata.TRUCK_NO = Vehicle_Number;
    } else {
      fdata.TRAILER_NO = formData.trailerNo;
    }
    showLoader();
    apiPostMethod(`${apiBaseUrl}EmptyVehicleArrival/addOrUpdateVehicleArrival`, fdata)
      .then((response) => {
        const { data } = response;
        console.log("Result Data : ". response);

        if (data.success) {
          form.resetForm();
          onAdded();
          RefreshPage();
        } else if (data.error) {
          errorToast(data.error);
        }
      })
      .catch((error) => {
        errorToast("Something went wrong, please try again after sometime");
      })
      .finally((a) => {
        hideLoader();
      });
  };
  const checktext = (e) => {
    if(e.which==32){
      return false;
    }
  }
  const form = useFormik({
    initialErrors : false,
    initialValues: {
      trailerNo: "",
      driverNo: "",
      plant: defaultPlantId, //defaultPlantId
    },
    validationSchema: Yup.object().shape({
      trailerNo: validation.required(),
      driverNo: validation.driverNumber,
      //plant: validation.required(),
    }),
    onSubmit(values) {},
  });

  const onVehicleNoChange = (e) =>{
    // console.log(e);
    // setTripSheetNo(e.tripsheet_no);
    const fdata = {Vehicle_Number}
    const {ZTRIPSHEET_NO, label, value, driver_name, driver_no}=e;
    apiPostMethod(`${apiBaseUrl}EmptyVehicleArrival/getTripsheetDetails`, fdata)
      .then((response) => {
        const { data } = response;
        let json_array = JSON.parse(data.results)
        let json_obj = json_array[0]
        console.log(json_obj);

        if(json_obj == undefined || json_obj == ""){
          errorToast("Please Enter Correct Vehicle No ...")
          return false
        }else{
        setTripSheetNo(json_obj.ZTRIPSHEET_NO)
        setDriverName(json_obj.ZZDRIVER_NAME)
        setDriverNo(json_obj.ZZDRIVER_PH_NO)
        setVehicleNoVerify(true)
        }

        if (data.success) {
          form.resetForm();
          onAdded();
        } else if (data.error) {
          errorToast(data.error);
        }
      })
      .catch((error) => {
        errorToast("Something went wrong, please try again after sometime");
      })
      .finally((a) => {
        hideLoader();
      });
    
  }


// console.log(form.setValues({...form.values}))
const [formData, setFormaData] = useState({});
const [TripSheetNo, setTripSheetNo] = useState('');
const [DriverName, setDriverName] = useState('');
const [DriverNo, setDriverNo] = useState('');
const [VehicleNoVerify,setVehicleNoVerify] = useState(false)

const updateData = (data) => {
  setFormaData(data);
};

const onTextChange = (e, key) => {
  const newData = {
    ...formData,
    [key]: e.target ? e.target.value : e.value,
  };
  updateData(newData);
};
const {
  Vehicle_Number,
} = formData;  
  return (
    <Row>
      <Col md="4" sm="12">
      <Label for="Vehicle_Number">Vehicle Number</Label>
          <InputGroup>
          <Input
            type="text"
            name="Vehicle_Number"
            value={Vehicle_Number}
            id="Vehicle_Number"
            disabled={VehicleNoVerify}
            onChange={(Vehicle_Number) => onTextChange(Vehicle_Number, "Vehicle_Number")}
            placeholder="Vehicle Number"
            maxLength="10"
          />
          <InputGroupText className="p-0">
                          <Button size="sm" color="success" 
                          style={{ height:'38px',width:'60px' }}
                          onClick={(e) => onVehicleNoChange(e)}
                          disabled={VehicleNoVerify}
                          >
                            {/* ✔️ */}
                            <Search size={25} style={{marginLeft:'10px' }} className="mr-1" />
                            {/* <i className="fa fa-check px-1"></i> */}
                          </Button>
          </InputGroupText>
          </InputGroup>
      </Col>
      <Col md="4" sm="12">
        <CustomTextInput label={"TripSheet No"} disabled={isTruck} isNumberOnly form={form} id="tripsheet_no" value={TripSheetNo} />
      </Col>
      <Col md="4" sm="12">
        <CustomTextInput label={"Driver Name"} disabled={isTruck} isNumberOnly form={form} id="driver_name" value={DriverName}/>
      </Col>
      <Col md="4" sm="12">
        <CustomTextInput label={"Driver No"} disabled={isTruck} isNumberOnly form={form} id="driverNo" value={DriverNo}/>
      </Col>
      <Col md="4" sm="12">
        <PlantIdDropdown form={form} id="plant" />
      </Col>
      <Col sm="12">
        <FormGroup className="d-flex justify-content-end mb-0">
          <div className="mr-1">
            <Button.Ripple outline color="primary" type="button" onClick={(e) => onAdd(statusCode.IN)}>
              <StopCircle size={16} className="mr-1" />
              Wait Outside
            </Button.Ripple> 
          </div>
          <Button.Ripple color="primary" type="button" onClick={(e) => onAdd((isTruck ? statusCode.FirstWeight : gateInStatus))} /*onClick={(e) => onAdd(gateInStatus)}*/>
            <Check size={16} className="mr-1" />
            Gate In
          </Button.Ripple>
        </FormGroup>
      </Col>
    </Row>
  );
};

export default IasEmptyVehicleArrivalForm;
